"""A shopping cart with item management and discount support.

This module provides a :class:`ShoppingCart` for accumulating priced items,
adjusting their quantities, and computing totals with an optional discount.
All monetary values are represented with :class:`decimal.Decimal` to avoid the
rounding errors inherent to binary floating point arithmetic.
"""

from __future__ import annotations

from dataclasses import dataclass, replace
from decimal import Decimal
from typing import Iterable


class ShoppingCartError(Exception):
    """Base class for all errors raised by :class:`ShoppingCart`."""


class ItemNotFoundError(ShoppingCartError):
    """Raised when an operation references a product not present in the cart."""

    def __init__(self, product_name: str) -> None:
        super().__init__(f"No item named {product_name!r} exists in the cart.")
        self.product_name = product_name


class DuplicateItemError(ShoppingCartError):
    """Raised when adding a product that is already present in the cart."""

    def __init__(self, product_name: str) -> None:
        super().__init__(
            f"An item named {product_name!r} is already in the cart; "
            "update its quantity instead of adding it again."
        )
        self.product_name = product_name


class InvalidPriceError(ShoppingCartError):
    """Raised when a unit price is zero or negative."""

    def __init__(self, unit_price: Decimal) -> None:
        super().__init__(f"Unit price must be greater than zero, got {unit_price}.")
        self.unit_price = unit_price


class InvalidQuantityError(ShoppingCartError):
    """Raised when a quantity is not a positive integer."""

    def __init__(self, quantity: int) -> None:
        super().__init__(f"Quantity must be a positive integer, got {quantity}.")
        self.quantity = quantity


class InvalidDiscountError(ShoppingCartError):
    """Raised when a discount value falls outside its permitted range."""

    def __init__(self, message: str) -> None:
        super().__init__(message)


@dataclass(frozen=True)
class CartItem:
    """An immutable line item: a product, its unit price, and its quantity."""

    product_name: str
    unit_price: Decimal
    quantity: int

    @property
    def line_total(self) -> Decimal:
        """Return the cost of this line: ``unit_price * quantity``."""
        return self.unit_price * self.quantity


class ShoppingCart:
    """A collection of priced items supporting a single optional discount.

    Items are keyed by product name, so each product appears at most once.
    Use :meth:`update_quantity` to change the count of an existing product
    rather than adding it twice.
    """

    def __init__(self) -> None:
        """Create an empty cart with no discount applied."""
        self._items: dict[str, CartItem] = {}
        self._discount: Decimal = Decimal("0")

    def add_item(
        self, product_name: str, unit_price: Decimal, quantity: int = 1
    ) -> CartItem:
        """Add a new product to the cart and return the created line item.

        Raises:
            DuplicateItemError: If the product is already in the cart.
            InvalidPriceError: If ``unit_price`` is not positive.
            InvalidQuantityError: If ``quantity`` is not a positive integer.
        """
        normalized_name = self._normalize_name(product_name)
        if normalized_name in self._items:
            raise DuplicateItemError(normalized_name)

        validated_price = self._validate_price(unit_price)
        validated_quantity = self._validate_quantity(quantity)

        item = CartItem(normalized_name, validated_price, validated_quantity)
        self._items[normalized_name] = item
        return item

    def remove_item(self, product_name: str) -> None:
        """Remove a product from the cart.

        Raises:
            ItemNotFoundError: If the product is not in the cart.
        """
        item = self._require_item(product_name)
        del self._items[item.product_name]

    def update_quantity(self, product_name: str, quantity: int) -> CartItem:
        """Set a new quantity for an existing product and return the line item.

        Raises:
            ItemNotFoundError: If the product is not in the cart.
            InvalidQuantityError: If ``quantity`` is not a positive integer.
        """
        existing_item = self._require_item(product_name)
        validated_quantity = self._validate_quantity(quantity)

        updated_item = replace(existing_item, quantity=validated_quantity)
        self._items[updated_item.product_name] = updated_item
        return updated_item

    def apply_percentage_discount(self, percentage: Decimal) -> None:
        """Apply a discount expressed as a percentage of the subtotal.

        Args:
            percentage: A value in the inclusive range ``[0, 100]``.

        Raises:
            InvalidDiscountError: If ``percentage`` is outside ``[0, 100]``.
        """
        if not Decimal("0") <= percentage <= Decimal("100"):
            raise InvalidDiscountError(
                f"Percentage discount must be between 0 and 100, got {percentage}."
            )
        self._discount = self.subtotal() * percentage / Decimal("100")

    def apply_flat_discount(self, amount: Decimal) -> None:
        """Apply a fixed-amount discount.

        Args:
            amount: A non-negative value not exceeding the current subtotal.

        Raises:
            InvalidDiscountError: If ``amount`` is negative or exceeds the subtotal.
        """
        if amount < Decimal("0"):
            raise InvalidDiscountError(
                f"Flat discount must not be negative, got {amount}."
            )
        if amount > self.subtotal():
            raise InvalidDiscountError(
                f"Flat discount {amount} exceeds the subtotal {self.subtotal()}."
            )
        self._discount = amount

    def clear_discount(self) -> None:
        """Remove any discount currently applied to the cart."""
        self._discount = Decimal("0")

    def subtotal(self) -> Decimal:
        """Return the sum of all line totals before any discount."""
        return sum(
            (item.line_total for item in self._items.values()), start=Decimal("0")
        )

    def total(self) -> Decimal:
        """Return the subtotal minus the applied discount, never below zero."""
        return max(self.subtotal() - self._discount, Decimal("0"))

    def list_items(self) -> tuple[CartItem, ...]:
        """Return all line items in insertion order as an immutable tuple."""
        return tuple(self._items.values())

    def clear(self) -> None:
        """Remove all items and any applied discount."""
        self._items.clear()
        self.clear_discount()

    def __len__(self) -> int:
        """Return the number of distinct products in the cart."""
        return len(self._items)

    def __contains__(self, product_name: object) -> bool:
        """Return whether a product name is present in the cart."""
        if not isinstance(product_name, str):
            return False
        return self._normalize_name(product_name) in self._items

    def __iter__(self) -> Iterable[CartItem]:
        """Iterate over the cart's line items in insertion order."""
        return iter(self._items.values())

    def _require_item(self, product_name: str) -> CartItem:
        """Return the line item for ``product_name`` or raise if it is absent."""
        normalized_name = self._normalize_name(product_name)
        item = self._items.get(normalized_name)
        if item is None:
            raise ItemNotFoundError(normalized_name)
        return item

    @staticmethod
    def _normalize_name(product_name: str) -> str:
        """Return a canonical product name, rejecting blank input."""
        normalized_name = product_name.strip()
        if not normalized_name:
            raise ItemNotFoundError(product_name)
        return normalized_name

    @staticmethod
    def _validate_price(unit_price: Decimal) -> Decimal:
        """Return ``unit_price`` if it is positive, otherwise raise."""
        if unit_price <= Decimal("0"):
            raise InvalidPriceError(unit_price)
        return unit_price

    @staticmethod
    def _validate_quantity(quantity: int) -> int:
        """Return ``quantity`` if it is a positive integer, otherwise raise.

        ``bool`` is explicitly rejected because it is a subclass of ``int``.
        """
        if isinstance(quantity, bool) or not isinstance(quantity, int):
            raise InvalidQuantityError(quantity)
        if quantity <= 0:
            raise InvalidQuantityError(quantity)
        return quantity
